#!/usr/bin/env python3
"""
Script para aplicar as correções do FitLog diretamente nos arquivos,
sem depender de `git apply` (evita problemas de patch corrompido por
conversão de quebra de linha no download).

Rode a partir da raiz do repositório fitlog:
    python3 apply_fixes.py
"""
import base64
import os
import sys

FILES = {
    'app.py': {
        "marker": 'em_producao = not (app.config.get',
        "b64": '',
    },
    'config.py': {
        "marker": 'config_class is ProductionConfig and not config_class.SECRET_KEY',
        "b64": '',
    },
    'repositories/registro_repository.py': {
        "marker": 'from models import db, RegistroTreino, HistoricoTreino',
        "b64": '',
    },
    'repositories/treino_repository.py': {
        "marker": 'from models import db, Treino',
        "b64": '',
    },
    'repositories/versao_repository.py': {
        "marker": 'from models import db, VersaoGlobal, TreinoVersao, VersaoExercicio',
        "b64": '',
    },
    'services/musculo_service.py': {
        "marker": 'from models import db, Musculo',
        "b64": '',
    },
    'tests/integration/test_routes/test_auth_routes.py': {
        "marker": 'Senha1234',
        "b64": '',
    },
    'utils/version_utils.py': {
        "marker": 'from models import Treino',
        "b64": '',
    },
}

def main():
    root = os.getcwd()
    if not os.path.isfile(os.path.join(root, "app.py")):
        print("ERRO: rode este script a partir da raiz do repositorio fitlog (onde fica o app.py).")
        sys.exit(1)

    aplicados, ja_ok, erros = [], [], []
    for rel_path, info in FILES.items():
        full_path = os.path.join(root, rel_path)
        if not os.path.isfile(full_path):
            erros.append(f"{rel_path}: arquivo nao encontrado")
            continue

        with open(full_path, "r", encoding="utf-8", errors="replace") as f:
            current = f.read()

        if info["marker"] in current:
            ja_ok.append(rel_path)
            continue

        novo_conteudo = base64.b64decode(info["b64"])
        with open(full_path, "wb") as f:
            f.write(novo_conteudo)
        aplicados.append(rel_path)

    print("\n=== Resultado ===")
    for p in aplicados:
        print(f"  [corrigido] {p}")
    for p in ja_ok:
        print(f"  [ja estava ok] {p}")
    for p in erros:
        print(f"  [ERRO] {p}")

    if erros:
        sys.exit(1)

    print("\nPronto. Rode `git status` e `git diff` para conferir, depois rode os testes.")

if __name__ == "__main__":
    main()